    pub async fn sole(self) -> Result<UserWithRelations> {
        let mut rows = self.limit(2).get().await?;
        match rows.len() {
            0 => anyhow::bail!("sole: no record found"),
            1 => Ok(rows.remove(0)),
            _ => anyhow::bail!("sole: multiple records found"),
        }
    }

